# Basic Reflex Agent - Vacuum Cleaner World
# PEAS: Performance=cleanliness, Environment=grid, Actuators=move/suck, Sensors=location/dirt

class VacuumReflexAgent:
    def __init__(self):
        self.location = 'A'  # Initial location

    def perceive(self, env_state):
        """Sensors: Get current location and dirt status"""
        return env_state.get(self.location, False)

    def act(self, dirt_present):
        """Actuators: Simple rule-based action"""
        if dirt_present:
            return 'Suck'
        else:
            # Move to other location
            return 'Move'

# Environment simulation
class Environment:
    def __init__(self):
        self.state = {'A': True, 'B': False}  # A is dirty, B is clean

    def execute(self, agent, action):
        if action == 'Suck':
            self.state[agent.location] = False
            print(f"Sucked dirt at {agent.location}")
        elif action == 'Move':
            agent.location = 'B' if agent.location == 'A' else 'A'
            print(f"Moved to {agent.location}")

# Run simulation
agent = VacuumReflexAgent()
env = Environment()

for step in range(4):
    print(f"\nStep {step + 1}: Agent at {agent.location}")
    dirt = env.execute(agent, 'Suck' if env.state.get(agent.location) else 'Move') or env.state.get(agent.location)
    percept = agent.perceive(env.state)
    action = agent.act(percept)
    env.execute(agent, action)
